// TypeScript implementation for Union Types
interface UnionTypesPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processUnionTypes(item: UnionTypesPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processUnionTypes({ id: 1, title: 'Union Types', status: 'active' }));

